mapper.select:

WHERE n.user_id = #{userId}

    AND n.folder_id = #{folderId}


    AND (
        n.title ILIKE CONCAT('%', #{keyword}, '%')
        OR COALESCE(n.summary, '') ILIKE CONCAT('%', #{keyword}, '%')
        OR n.content ILIKE CONCAT('%', #{keyword}, '%')
    )


    AND EXISTS (
        SELECT 1
        FROM note_tag_rel r
        INNER JOIN note_tag t ON r.tag_id = t.id
        WHERE r.note_id = n.id
          AND t.name = #{tagName}
    )

ORDER BY n.updated_at DESC

mapper.update:
UPDATE note
SET is_shared = #{shared},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE
FROM note
WHERE id = #{id}
  AND user_id = #{userId}

mapper.select:

WHERE n.user_id = #{userId}
ORDER BY n.updated_at DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM note
WHERE user_id = #{userId}
